std::span<const Item> glyph::items() { return g_items; }
std::span<const Section> glyph::sections() { return g_sections; }

const Item *glyph::lookup(std::string_view character) {
  auto it = std::lower_bound(g_index.begin(), g_index.end(), character,
                             [](const Item *i, std::string_view key) { return i->character < key; });
  if (it != g_index.end() && (*it)->character == character) return *it;
  return nullptr;
}

std::string_view glyph::categoryLabel(Category category) {
  switch (category) {
  case Category::SmileysAndEmotion:
    return "Smileys & Emotion";
  case Category::PeopleAndBody:
    return "People & Body";
  case Category::AnimalsAndNature:
    return "Animals & Nature";
  case Category::FoodAndDrink:
    return "Food & Drink";
  case Category::TravelAndPlaces:
    return "Travel & Places";
  case Category::Activities:
    return "Activities";
  case Category::Objects:
    return "Objects";
  case Category::Symbols:
    return "Symbols";
  case Category::Flags:
    return "Flags";
  case Category::Math:
    return "Math";
  case Category::Arrows:
    return "Arrows";
  case Category::Currency:
    return "Currency";
  case Category::Punctuation:
    return "Punctuation";
  case Category::Shapes:
    return "Shapes";
  case Category::MiscSymbols:
    return "Misc Symbols";
  case Category::Greek:
    return "Greek";
  case Category::NumberForms:
    return "Number Forms";
  case Category::FancyLetters:
    return "Fancy Letters";
  }
  return {};
}
